import java.math.BigDecimal;
import java.math.RoundingMode;

public class BigDecimalExample {

    public static void main(String[] args) {

        // Defining BigDecimal numbers
        BigDecimal num1 = new BigDecimal("10.1234");
        BigDecimal num2 = new BigDecimal("20.4567");

        // Performing addition
        BigDecimal result = num1.add(num2);

        // Rounding to three decimal places with HALF_UP rounding mode
        BigDecimal roundedResult = result.setScale(3, RoundingMode.HALF_UP);

        // Printing the result
        System.out.println("The result of adding " + num1 + " and " + num2 + " is " + roundedResult + ".");

        // Trying out different rounding modes
        System.out.println("\nRounding modes demo:");
        System.out.println("HALF_EVEN: " + result.setScale(2, RoundingMode.HALF_EVEN));
        System.out.println("CEILING: " + result.setScale(2, RoundingMode.CEILING));
        System.out.println("FLOOR: " + result.setScale(2, RoundingMode.FLOOR));
        System.out.println("DOWN: " + result.setScale(2, RoundingMode.DOWN));
        System.out.println("UP: " + result.setScale(2, RoundingMode.UP));
    }
}
